import { arrayMove } from '@dnd-kit/sortable';

const handleDragEnd = (event, orderedColumns, setOrderedColumns) => {
  const { active, over } = event;

  if (!over || active.id === over.id) return;

  const activeColumn = orderedColumns.find(c => c.cards.some(card => card._id === active.id));
  if (!activeColumn) return;

  const oldIndex = activeColumn.cards.findIndex(c => c._id === active.id);
  const newIndex = activeColumn.cards.findIndex(c => c._id === over.id);

  const dndOrderedCards = arrayMove(activeColumn.cards, oldIndex, newIndex);
  const dndOrderedCardIds = dndOrderedCards.map(c => c._id);

  const newColumns = orderedColumns.map(c => {
    if (c._id === activeColumn._id) {
      return { ...c, cards: dndOrderedCards, cardOrderIds: dndOrderedCardIds };
    }
    return c;
  });

  setOrderedColumns(newColumns);
};
